import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import './Pages.css';

const CloseAccount = () => {
  const [language, setLanguage] = useState('en');
  const [customers, setCustomers] = useState([]);
  const [selectedCustomer, setSelectedCustomer] = useState('');
  const [searchName, setSearchName] = useState('');
  const [filteredCustomers, setFilteredCustomers] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [accountDetails, setAccountDetails] = useState(null);
  const [bills, setBills] = useState([]);
  const [interestRate, setInterestRate] = useState(7);
  const [paymentDate, setPaymentDate] = useState(new Date().toISOString().split('T')[0]);
  const [paymentAmount, setPaymentAmount] = useState(0);
  const [isPartialPayment, setIsPartialPayment] = useState(false);

  const translations = {
    en: { closeAccount: 'Close Account', selectCustomer: 'Select Customer', 
      pending: 'Pending Balance', interest: 'Interest %', days: 'Days', finalAmount: 'Final Amount', pay: 'Pay', partialPayment: 'Partial Payment' },
    te: { closeAccount: 'ఖాతా మూసివేయి', selectCustomer: 'కస్టమర్‌ను ఎంచుకోండి', 
      pending: 'బకాయి బ్యాలెన్స్', interest: 'వడ్డీ %', days: 'రోజులు', finalAmount: 'తుది మొత్తం', pay: 'చెల్లించండి', partialPayment: 'పాక్షిక చెల్లింపు' },
    hi: { closeAccount: 'खाता बंद करें', selectCustomer: 'ग्राहक चुनें', 
      pending: 'बकाया शेष', interest: 'ब्याज %', days: 'दिन', finalAmount: 'अंतिम राशि', pay: 'भुगतान करें', partialPayment: 'आंशिक भुगतान' }
  };

  const t = translations[language] || translations.en;

  useEffect(() => {
    fetchCustomers();
  }, []);

  const fetchCustomers = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/accounts/customers', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCustomers(response.data.accounts || []);
    } catch (err) {
      console.error('Error:', err);
    }
  };

  const handleSearchChange = (value) => {
    setSearchName(value);

    if (!value.trim()) {
      setFilteredCustomers([]);
      setShowSuggestions(false);
      return;
    }

    const filtered = customers.filter(c =>
      c.customerName.toLowerCase().includes(value.toLowerCase())
    );

    setFilteredCustomers(filtered);
    setShowSuggestions(true);
  };

  const handleSelectSuggestion = async (customer) => {
    setSearchName(customer.customerName);
    setShowSuggestions(false);
    setSelectedCustomer(customer._id);
    await handleSelectCustomer(customer._id);
  };

  const handleSelectCustomer = async (customerId) => {
    setSelectedCustomer(customerId);
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`http://localhost:5000/api/accounts/${customerId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setAccountDetails(response.data.account || response.data);
      setBills(response.data.bills || []);
    } catch (err) {
      console.error('Error:', err);
    }
  };

  const handleCloseAccount = async () => {
    if (!selectedCustomer || paymentAmount <= 0) {
      alert('Please select a customer and enter payment amount');
      return;
    }

    const finalAmount = calculateFinalAmount();
    if (paymentAmount > finalAmount && !isPartialPayment) {
      alert('Payment amount cannot exceed the final amount for full payment');
      return;
    }

    try {
      const token = localStorage.getItem('token');
      const response = await axios.post('http://localhost:5000/api/accounts/close', {
        customerId: selectedCustomer,
        interestPercentage: interestRate,
        paymentAmount: parseFloat(paymentAmount),
        partialPayment: isPartialPayment,
        paymentDate: paymentDate
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });

      alert('Account closed successfully!');
      // Reset form
      setSelectedCustomer('');
      setAccountDetails(null);
      setBills([]);
      setPaymentAmount(0);
      setIsPartialPayment(false);
      // Refresh customers list
      fetchCustomers();
    } catch (err) {
      console.error('Error:', err);
      alert('Error closing account: ' + (err.response?.data?.message || err.message));
    }
  };

  const calculateFinalAmount = () => {
    if (!bills.length || !paymentDate) return 0;
    
    const paymentDateObj = new Date(paymentDate);
    let totalWithInterest = 0;
    
    bills.forEach(bill => {
      if (bill.pendingAmount > 0) {
        const purchaseDateObj = new Date(bill.purchaseDate);
        const daysDiff = Math.floor((paymentDateObj - purchaseDateObj) / (1000 * 60 * 60 * 24));
        const interest = (bill.pendingAmount * interestRate * daysDiff) / (365 * 100);
        totalWithInterest += bill.pendingAmount + interest;
      }
    });
    
    return totalWithInterest;
  };

  return (
    <div className="dashboard-layout">
      <Sidebar language={language} />
      <div className="main-content">
        <div className="top-bar">
          <h1>{t.closeAccount}</h1>
          <select value={language} onChange={(e) => setLanguage(e.target.value)} className="language-selector">
            <option value="en">English</option>
            <option value="te">Telugu</option>
            <option value="hi">Hindi</option>
          </select>
        </div>

            <div className="page-card">
            <div className="form-group" style={{ position: 'relative' }}>
              <label>Search Customer</label>
              <input
                type="text"
                placeholder="Type name..."
                value={searchName}
                onChange={(e) => handleSearchChange(e.target.value)}
                style={{ padding: '10px', width: '100%' }}
              />

              {showSuggestions && filteredCustomers.length > 0 && (
                <div style={{
                  position: 'absolute',
                  background: '#fff',
                  border: '1px solid #ddd',
                  width: '100%',
                  maxHeight: '200px',
                  overflowY: 'auto',
                  zIndex: 1000
                }}>
                  {filteredCustomers.map(c => (
                    <div
                      key={c._id}
                      onClick={() => handleSelectSuggestion(c)}
                      style={{ padding: '10px', cursor: 'pointer' }}
                    >
                      <strong>{c.customerName}</strong><br />
                      <small>{c.phone} | {c.village}</small>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="form-group">
              <label>{t.selectCustomer}</label>
              <select value={selectedCustomer} onChange={(e) => handleSelectCustomer(e.target.value)}>
                <option value="">-- {t.selectCustomer} --</option>
                {customers.map(c => <option key={c._id} value={c._id}>{c.customerName}</option>)}
              </select>
            </div>

            {accountDetails && (
            <div className="close-account-details">
              <h2>Account Details</h2>
              <p>{t.pending}: ₹ {accountDetails.pendingBalance?.toFixed(2)}</p>
              
              <div className="form-group">
                <label>Payment Date</label>
                <input type="date" value={paymentDate} onChange={(e) => setPaymentDate(e.target.value)} />
              </div>
              
              <div className="form-group">
                <label>{t.interest}</label>
                <input type="number" value={interestRate} onChange={(e) => setInterestRate(e.target.value)} />
              </div>

              <table className="bills-table">
                <thead>
                  <tr>
                    <th>Purchase Date</th>
                    <th>Total Amount</th>
                    <th>Paid Amount</th>
                    <th>Remaining</th>
                    <th>Days</th>
                    <th>Interest</th>
                    <th>Total with Interest</th>
                  </tr>
                </thead>
                <tbody>
                  {bills.map((bill, index) => {
                    const purchaseDateObj = new Date(bill.purchaseDate);
                    const paymentDateObj = new Date(paymentDate);
                    const daysDiff = Math.floor((paymentDateObj - purchaseDateObj) / (1000 * 60 * 60 * 24));
                    const interest = bill.pendingAmount > 0 ? (bill.pendingAmount * interestRate * daysDiff) / (365 * 100) : 0;
                    const totalWithInterest = bill.pendingAmount + interest;
                    
                    return (
                      <tr key={index}>
                        <td>{purchaseDateObj.toLocaleDateString()}</td>
                        <td>₹ {bill.grandTotal?.toFixed(2)}</td>
                        <td>₹ {bill.paidAmount?.toFixed(2)}</td>
                        <td>₹ {bill.pendingAmount?.toFixed(2)}</td>
                        <td>{daysDiff}</td>
                        <td>₹ {interest.toFixed(2)}</td>
                        <td>₹ {totalWithInterest.toFixed(2)}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>

              <div className="total-box">
                <p className="total-label">{t.finalAmount}</p>
                <p className="total-value">₹ {calculateFinalAmount().toFixed(2)}</p>
              </div>

              <div className="form-group">
                <label>Payment Amount</label>
                <input type="number" value={paymentAmount} onChange={(e) => setPaymentAmount(e.target.value)} />
              </div>

              <div className="form-group">
                <label>
                  <input type="checkbox" checked={isPartialPayment} onChange={(e) => setIsPartialPayment(e.target.checked)} />
                  {t.partialPayment}
                </label>
              </div>

              <button className="save-btn" onClick={handleCloseAccount}>{t.pay}</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CloseAccount;
